// ---------------- UTIL ----------------
const rnd = (n) => Math.floor(Math.random() * n);
const pick = (arr) => arr[rnd(arr.length)];

function eligibleFor(player, slotRole) {
  const accepts = SLOT_ACCEPTS[slotRole] || [slotRole];
  const roles = player.rg && player.rg.length ? player.rg : [player.r];
  return roles.some(r => accepts.includes(r)) || accepts.includes(player.r);
}

// ---------------- SIMULAZIONE RECORD ----------------
// Calcola un punteggio squadra 0-100 e proietta record 38 partite
function simulate(squad, bonusTotal = 0) {
  const filled = squad.filter(Boolean);
  if (filled.length === 0) return null;

  const avg = filled.reduce((s,p)=>s+p.rt,0) / filled.length;

  // Penalità di sicurezza: se manca il portiere (non dovrebbe mai capitare).
  const gk = filled.filter(p=>p.slot==="GK").length;
  const penalty = gk === 1 ? 0 : -8;

  // ---- CHIMICA "scegliibile": premia blocchi di stesso club e stessa stagione ----
  // Per ogni club, il blocco di n giocatori vale n*(n-1)/2 "legami" (più grande il blocco, più cresce).
  const clubCount = {}, seasonCount = {};
  filled.forEach(p => {
    clubCount[p.c] = (clubCount[p.c]||0)+1;
    seasonCount[p.s] = (seasonCount[p.s]||0)+1;
  });
  const links = (counts) => Object.values(counts)
    .reduce((s,n)=> s + (n>=2 ? n*(n-1)/2 : 0), 0);
  const clubLinks   = links(clubCount);     // max 55 (tutti stesso club)
  const seasonLinks = links(seasonCount);   // max 55 (tutti stessa stagione)

  // chimica club pesa di più (legame più forte) della stagione.
  // peso MEDIO: vale qualche punto e può spostare il tier, ma non è risolutiva.
  // blocco 2≈0.3, 4≈1.7, 6≈3.2, 8+≈4.5 (cap)
  const chemRaw = clubLinks * 0.14 + seasonLinks * 0.06;
  const chem = Math.min(4.5, chemRaw);

  // forza = media reale + chimica + bonus pre-partita (Capitano/Allenatore/Super Sub)
  const strength = avg + penalty + chem + bonusTotal;

  // REBALANCE: stima record coerente col motore (denom 20). Curva più dolce e
  // conservativa: il 38-0 stimato richiede una rosa eccezionale, come nei risultati reali.
  const t = Math.max(0, Math.min(1, (strength - 72) / 20));
  const winRate = Math.pow(t, 1.05) * 0.96;
  const wins = Math.round(38 * winRate);
  const remaining = 38 - wins;
  const drawShare = 0.34 + 0.13 * (1 - winRate);
  const draws = Math.round(remaining * drawShare);
  const losses = 38 - wins - draws;
  const points = wins*3 + draws;

  return {
    strength: Math.round(strength*10)/10,
    avg: Math.round(avg*10)/10,
    wins, draws, losses, points,
    chem: Math.round(chem*10)/10,
    bonus: Math.round(bonusTotal*10)/10,
    tier: tierFor(points, wins),
  };
}

function tierFor(points, wins) {
  if (wins === 38) return { name: "38-0 LEGGENDARIO", color: "#ffd24a", emoji: "🏆" };
  if (points >= 100) return { name: "Stagione Storica", color: "#ffd24a", emoji: "👑" };
  if (points >= 86) return { name: "Campioni d'Italia", color: "#6ee7a8", emoji: "🥇" };
  if (points >= 72) return { name: "Champions League", color: "#7ec8ff", emoji: "⭐" };
  if (points >= 58) return { name: "Europa League", color: "#b6e36e", emoji: "✨" };
  if (points >= 45) return { name: "Metà Classifica", color: "#e0e0e0", emoji: "➖" };
  return { name: "Lotta Salvezza", color: "#ff8e8e", emoji: "⚠️" };
}

// tier basato sulla POSIZIONE in classifica (coerente con la tabella finale)
// posizioni Serie A: 1 scudetto · 2-4 Champions · 5-6 Europa · 7 Conference · 8-15 metà · 18-20 retrocessione
function tierForPosition(pos, wins) {
  if (wins === 38) return { name: "38-0 LEGGENDARIO", color: "#ffd24a", emoji: "🏆" };
  if (pos === 1)  return { name: "Campioni d'Italia", color: "#ffd24a", emoji: "🏆" };
  if (pos <= 4)   return { name: "Champions League", color: "#7ec8ff", emoji: "⭐" };
  if (pos <= 6)   return { name: "Europa League", color: "#b6e36e", emoji: "✨" };
  if (pos === 7)  return { name: "Conference League", color: "#a0e07e", emoji: "🌍" };
  if (pos <= 15)  return { name: "Metà Classifica", color: "#e0e0e0", emoji: "➖" };
  if (pos <= 17)  return { name: "Bassa Classifica", color: "#ffb38e", emoji: "🔻" };
  return { name: "Retrocessione", color: "#ff8e8e", emoji: "⚠️" };
}

// ---------------- SIMULAZIONE GIORNATA PER GIORNATA ----------------
// 38 partite con gol estratti da Poisson, calibrati sulla forza della squadra.
// Seed deterministico: lo stesso XI produce sempre lo stesso calendario.

// generatore pseudo-casuale deterministico (mulberry32)
function mulberry32(seed) {
  return function() {
    seed |= 0; seed = (seed + 0x6D2B79F5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
// estrae k da Poisson(lambda) con generatore rng
function poisson(lambda, rng) {
  const L = Math.exp(-lambda);
  let k = 0, p = 1;
  do { k++; p *= rng(); } while (p > L);
  return k - 1;
}

// ================== ONDATA 4: MOTORE DI EVOLUZIONE (carriera) ==================
// Crescita in base al gap Potenziale-Overall, declino in base all'età.
// Il range (basso/alto) è modulato dal rendimento della stagione:
//   perf = scarto posizione attesa - reale (>0 = sopra le attese).

// crescita per gap POT-OVR -> [min, max]
function growthRange(gap) {
  if (gap >= 20) return [4, 7];
  if (gap >= 15) return [3, 5];
  if (gap >= 10) return [2, 4];
  if (gap >= 5)  return [1, 3];
  if (gap >= 2)  return [0, 2];
  if (gap >= 0)  return [-1, 1];
  return [0, 0];
}
// declino per età -> [min, max] (valori negativi)
function declineRange(age) {
  if (age <= 24) return [0, 0];
  if (age <= 28) return [-1, 0];
  if (age <= 31) return [-2, -1];
  if (age <= 34) return [-3, -2];
  if (age <= 37) return [-5, -3];
  return [-8, -5];
}
// fattore rendimento 0..1: dove cade nel range. perf scarto attese-reale.
// sopra le attese -> verso il massimo; sotto -> verso il minimo.
function perfFactor(perf) {
  // perf tipico -10..+10 -> clamp e normalizza a 0..1 centrato su 0.5
  const t = Math.max(-6, Math.min(6, perf)) / 12 + 0.5;
  return t;
}
// evolve un singolo giocatore di una stagione. Ritorna {nrt, npot, delta, dGrow, dDecl}
function evolvePlayer(p, perf, rng) {
  const gap = (p.pot ?? p.rt) - p.rt;
  const [gLo, gHi] = growthRange(gap);
  const [dLo, dHi] = declineRange(p.age ?? 27);
  const f = perfFactor(perf);
  // interpolazione nel range, con un filo di rumore deterministico
  const jitter = (rng() - 0.5) * 0.6;
  const grow = Math.round(gLo + (gHi - gLo) * Math.max(0, Math.min(1, f + jitter)));
  const decl = Math.round(dHi + (dLo - dHi) * Math.max(0, Math.min(1, f + jitter))); // f alto = declino minore
  const delta = grow + decl;
  let nrt = Math.max(40, Math.min(99, p.rt + delta));
  const npot = Math.max(nrt, p.pot ?? p.rt); // il potenziale non scende sotto l'OVR
  return { nrt, npot, delta: nrt - p.rt, dGrow: grow, dDecl: decl };
}
// evolve l'intera rosa di una stagione di carriera
function evolveSquad(squad, perf, seed) {
  const rng = mulberry32((seed ^ 0x4f1bbcdc) >>> 0);
  return squad.map(p => {
    if (!p) return p;
    const ev = evolvePlayer(p, perf, rng);
    return { ...p, rt: ev.nrt, pot: ev.npot, age: (p.age ?? 27) + 1, _evo: ev };
  });
}

// Forza di ogni club in OGNI stagione = media top-11 rating di quella rosa.
// Se la rosa ha meno di 11 giocatori con dati, i mancanti contano come overall 69.
const CLUB_STRENGTH_BY_SEASON = (() => {
  const byCS = {};
  PLAYERS.forEach(p => { const k = p.c+"|"+p.s; (byCS[k] = byCS[k] || []).push(p); });
  const out = {};
  for (const [k, arr] of Object.entries(byCS)) {
    const top = arr.map(p=>p.rt).sort((a,b)=>b-a).slice(0,11);
    while (top.length < 11) top.push(69);           // riempi i buchi con 69
    out[k] = top.reduce((s,r)=>s+r,0)/11;
  }
  return out;
})();

// stagioni SIMULABILI come campionato (escluse Legends e annate incomplete)
const ALL_SEASONS = REAL_SEASONS.filter(s => !INCOMPLETE_SEASONS.includes(s));

// avversarie reali di una stagione: tutti i club dell'annata, poi tieni le 19 più forti
// (così con la tua squadra il campionato è sempre a 20). Toglie le più deboli se necessario.
// excludeClub: in Modalità Squadra prendi TU il posto di quel club, quindi va rimosso dalle
// avversarie; al suo posto entra automaticamente la 20ª per forza (lo slice(0,19) ripesca).
function opponentsForSeason(season, excludeClub = null) {
  return Object.entries(CLUB_STRENGTH_BY_SEASON)
    .filter(([k]) => k.endsWith("|"+season))
    .map(([k, str]) => ({ club: k.split("|")[0], str, season }))
    .filter(o => o.club !== excludeClub)
    .sort((a,b)=>b.str-a.str)
    .slice(0, 19);
}

// Calendario: ogni avversaria affrontata 2 volte (andata/ritorno), una casa una trasferta.
function buildFixtures(rng, opponents) {
  const order = [...opponents];
  for (let i=order.length-1;i>0;i--){ const j=Math.floor(rng()*(i+1)); [order[i],order[j]]=[order[j],order[i]]; }
  const fixtures = [];
  const n = order.length;
  order.forEach((o, i) => fixtures.push({ ...o, home: i % 2 === 0, round: i+1 }));
  order.forEach((o, i) => fixtures.push({ ...o, home: i % 2 !== 0, round: i+1+n }));
  return fixtures;
}

// converte un rating-forza club (~70-86) in scala 0..1 usata dal motore gol
// REBALANCE difficoltà: denominatore 20 (satura a 92, era 13/85) -> la curva sale
// gradualmente e premia rose davvero forti; dominare richiede una squadra quasi perfetta.
const strToT = (s) => Math.max(0, Math.min(1, (s - 72) / 20));

function ordinaleNews(n) { return `${n}°`; }

function simulateSeason(squad, baseSim, forcedSeason, meta = {}) {
  const filled = squad.filter(Boolean);
  const strength = baseSim.strength;
  // forza relativa 0..1 (stesso mapping del record, denom 20)
  const tStr = Math.max(0, Math.min(1, (strength - 72) / 20));
  // attacco/difesa attesi: la forza pesa molto (top team segna tanto e subisce pochissimo)
  // REBALANCE: difesa più severa in cima (def 2.2 -> 0.2) per rendere il 38-0 un vero traguardo.
  const teamAtt = 0.7 + tStr * 2.8;      // gol fatti attesi (0.7 .. 3.5)
  const teamDef = 2.2 - tStr * 2.0;      // gol subiti attesi (2.2 .. 0.2)

  const seed = filled.reduce((s,p)=>s + p.pid*7 + p.rt, filled.length*1000);
  const rng = mulberry32(seed);

  // pesi marcatori: attaccanti molto probabili, poi ali/trequartisti, poi centrocampo, raramente difesa
  const scorerWeight = (p) => {
    if (["ST"].includes(p.slot)) return 10;
    if (["RW","LW","CAM"].includes(p.slot)) return 6;
    if (["CM","CDM"].includes(p.slot)) return 2.5;
    if (["RB","LB"].includes(p.slot)) return 1;
    if (p.slot === "CB") return 0.7;
    return 0; // GK
  };
  const pool = filled.filter(p=>scorerWeight(p)>0);
  const totW = pool.reduce((s,p)=>s+scorerWeight(p),0);
  const pickScorer = () => {
    let r = rng()*totW;
    for (const p of pool){ r -= scorerWeight(p); if (r<=0) return p.n; }
    return pool[0].n;
  };
  const minutes = (n) => {
    const arr = [];
    for (let i=0;i<n;i++) arr.push(1 + Math.floor(rng()*90));
    return arr.sort((a,b)=>a-b);
  };

  // STAGIONE: se l'utente ne ha scelta una reale la usiamo, altrimenti pescata
  // casualmente (deterministica dal seed). Definisce le avversarie reali.
  let playedSeason;
  if (forcedSeason && ALL_SEASONS.includes(forcedSeason)) {
    playedSeason = forcedSeason;
  } else {
    const seasonIdx = Math.floor(mulberry32(seed ^ 0x5bf03635)() * ALL_SEASONS.length);
    playedSeason = ALL_SEASONS[seasonIdx];
  }
  const opponents = opponentsForSeason(playedSeason, meta.excludeClub || null);

  // calendario: avversarie reali della stagione, andata e ritorno
  const fixtures = buildFixtures(rng, opponents);
  const nGames = fixtures.length;

  let W=0,D=0,L=0,GF=0,GA=0;
  const matches = fixtures.map((f) => {
    const oppT = strToT(f.str);                 // forza avversario 0..1
    const homeAdv = f.home ? 1.10 : 0.93;
    const lamFor = Math.max(0.12, teamAtt * homeAdv * (1.15 - oppT*0.95));
    const lamAga = Math.max(0.06, (teamDef / homeAdv) * (0.45 + oppT*1.15));
    const gf = Math.min(8, poisson(lamFor, rng));
    const ga = Math.min(8, poisson(lamAga, rng));
    GF += gf; GA += ga;
    let res;
    if (gf > ga) { W++; res="W"; } else if (gf === ga) { D++; res="D"; } else { L++; res="L"; }
    const ourMin = minutes(gf);
    const scorers = ourMin.map(min => ({ name: pickScorer(), min }));
    const oppMin = minutes(ga);
    return { round: f.round, opp: f.club, home: f.home, gf, ga, res, scorers, oppMin };
  }).sort((a,b)=>a.round-b.round);

  const points = W*3 + D;

  // ---- CLASSIFICA: le avversarie reali della stagione + la tua squadra ----
  // I PUNTI delle avversarie hanno una scala PROPRIA (più ripida del motore-difficoltà):
  // così una big resta una big (~85-94 pt) indipendentemente dal ribilanciamento della
  // TUA difficoltà. oppToT usa denom 13; la curva ricrea punteggi storici realistici.
  const oppToT = (s) => Math.max(0, Math.min(1, (s - 72) / 13));
  const expectedPoints = (t) => Math.round(18 + t * 60 + Math.pow(t, 1.8) * 16);
  // i MIEI punti attesi: stessa scala delle avversarie ma a partire dalla mia forza,
  // così il confronto in classifica è equo. (strength tua su scala club: avg+chimica+bonus)
  const myOppT = oppToT(strength);

  // posizione ATTESA: confronto i punti attesi mio vs avversarie (deterministico)
  const expectedTable = [
    { club: "LA TUA SQUADRA", t: myOppT, pts: expectedPoints(myOppT), me: true },
    ...opponents.map(o => ({ club: o.club, t: oppToT(o.str), pts: expectedPoints(oppToT(o.str)), me: false })),
  ].sort((a,b)=>b.pts-a.pts);
  const expectedPos = expectedTable.findIndex(r => r.me) + 1;

  // posizione REALE: i miei punti veri + punti simulati delle avversarie (con casualità).
  const rng2 = mulberry32(seed ^ 0x9e3779b9);
  const oppResults = opponents.map(o => {
    const t = oppToT(o.str);
    const base = expectedPoints(t);
    const noise = Math.round((rng2()-0.5) * 12); // ±6 punti di varianza
    return { club: o.club, pts: Math.max(0, Math.min(98, base + noise)), me: false };
  });

  // ---- ONDATA 3+: EVENTI LIVE della stagione (flash news durante la simulazione) ----
  // Alcuni eventi PENALIZZANO un'avversaria (le tolgono punti -> cambia la classifica).
  // Altri colpiscono la TUA squadra (Super Sub, allenatore) o, raramente, ti penalizzano.
  const { coach: metaCoach, captain: metaCaptain, superSub: metaSub } = meta;
  const rngE = mulberry32(seed ^ 0x77f1e1d3);
  const liveEvents = [];
  const usedRounds = new Set();
  const freeRound = () => {
    for (let k=0;k<50;k++) {
      const r = 2 + Math.floor(rngE() * Math.max(1, nGames - 3));
      if (!usedRounds.has(r)) { usedRounds.add(r); return r; }
    }
    return 1 + Math.floor(rngE()*nGames);
  };
  // pool di avversarie ordinate per forza (le prime fanno più notizia)
  const rivalNames = [...oppResults].sort((a,b)=>b.pts-a.pts).map(o=>o.club);
  const penalizeRival = (club, pts) => {
    const o = oppResults.find(x => x.club === club);
    if (o) o.pts = Math.max(0, o.pts - pts);
  };
  // nome di un giocatore reale della rosa di quel club in quella stagione (per le plusvalenze)
  const rosterName = (club) => {
    const roster = PLAYERS.filter(p => p.c===club && p.s===playedSeason);
    if (!roster.length) return null;
    return roster[Math.floor(rngE()*roster.length)].n;
  };
  // penalità che colpisce la TUA squadra: la applichiamo direttamente ai punti.
  let myPenalty = 0;

  // PENALITÀ alle avversarie — con descrizioni chiare e qualche variante
  const illecitoVariants = [
    (c,p)=>`${c} perde 10 punti per illecito amministrativo: stipendi pagati "in nero" e non registrati a bilancio.`,
    (c,p)=>`10 punti di penalizzazione per ${c}: bilanci falsati per nascondere un buco finanziario enorme.`,
    (c,p)=>`${c} sanzionata con 10 punti: fatture per sponsorizzazioni inesistenti gonfiavano i ricavi del club.`,
  ];
  const sanzioneVariants = [
    (c,p)=>`${c} penalizzata di 6 punti: tesseramenti irregolari di alcuni giocatori in violazione del regolamento.`,
    (c,p)=>`6 punti in meno per ${c}: mancati pagamenti verso altri club e la lega hanno fatto scattare la sanzione.`,
    (c,p)=>`${c} colpita da 6 punti di penalizzazione per inadempienze federali nella gestione del tesseramento.`,
  ];
  const penaltyTemplates = [
    { pts: 15, label:"CASO PLUSVALENZE",
      txt:(c, p)=> p
        ? `${c} è stata penalizzata di 15 punti: ${p} è finito al centro di un caso di plusvalenze gonfiate, scambiato a un valore artificiale per truccare i bilanci.`
        : `${c} è stata penalizzata di 15 punti: plusvalenze gonfiate, cioè giocatori scambiati a valori artificiali per truccare i bilanci.` },
    { pts: 10, label:"ILLECITO AMMINISTRATIVO",
      txt:(c, p)=> illecitoVariants[Math.floor(rngE()*illecitoVariants.length)](c, p) },
    { pts: 6,  label:"SANZIONE FEDERALE",
      txt:(c, p)=> sanzioneVariants[Math.floor(rngE()*sanzioneVariants.length)](c, p) },
    { pts: 4,  label:"TIFOSERIA SQUALIFICATA",
      txt:(c, p)=>`${c} multata e penalizzata di 4 punti: cori e disordini della tifoseria hanno fatto scattare la chiusura della curva e una sanzione in classifica al club.` },
  ];
  const colorTemplates = [
    "🌧️ Maltempo in tutta la penisola: rinvii e campi al limite della praticabilità.",
    "🦠 Influenza di stagione: diverse squadre con le rose decimate.",
  ];

  // CAP per stagione (richiesta utente): MAI più di uno per tipo.
  //   - max 1 penalizzazione a una rivale
  //   - max 1 evento di colore (casuale)
  //   - max 1 evento contro la TUA squadra (penalità / Super Sub / allenatore)
  let ownEventDone = false;   // un solo evento contro di te
  let rivalPenDone = false;   // una sola penalizzazione a rivale
  let colorDone = false;      // un solo evento di colore

  // proviamo a piazzare un evento di ciascun tipo, ognuno con la sua probabilità.
  // L'ordine garantisce che "contro di te" sia valutato per primo (è il più raro).

  // 1) EVENTO CONTRO LA TUA SQUADRA (al massimo 1, e non garantito)
  {
    const roll = rngE();
    if (roll < 0.10) {
      // penalità amministrativa alla tua squadra
      const round = freeRound();
      const pts = [4,6][Math.floor(rngE()*2)];
      myPenalty += pts; ownEventDone = true;
      liveEvents.push({ round, kind:"own_penalty", title:"PENALIZZAZIONE",
        text:`Brutte notizie: la tua squadra è stata penalizzata di ${pts} punti per un'irregolarità amministrativa. La classifica ne risente.`,
        pts });
    } else if (metaSub && roll < 0.20) {
      const round = freeRound();
      const variants = [
        { ico:"🩹", what:`si è procurato un grave infortunio e chiude la stagione in anticipo` },
        { ico:"🚔", what:`è stato coinvolto in una vicenda giudiziaria ed è stato arrestato` },
        { ico:"🟥", what:`è stato squalificato a lungo dal giudice sportivo` },
      ];
      const v = variants[Math.floor(rngE()*variants.length)];
      const pts = 2 + Math.floor(rngE()*3);
      myPenalty += pts; ownEventDone = true;
      liveEvents.push({ round, kind:"own_player", title:"TEGOLA IN ROSA",
        text:`${v.ico} ${metaSub.n}, il tuo Super Sub, ${v.what}: la squadra perde una pedina e lascia per strada ${pts} punti.`,
        pts });
    } else if (metaCoach && roll < 0.28) {
      const round = freeRound();
      const pts = 2 + Math.floor(rngE()*2);
      myPenalty += pts; ownEventDone = true;
      liveEvents.push({ round, kind:"own_coach", title:"PANCHINA IN AFFANNO",
        text:`🤒 ${metaCoach.name} si è ammalato e salta diverse partite: senza la sua guida in panchina la squadra perde ${pts} punti.`,
        pts });
    }
  }

  // 2) PENALIZZAZIONE A UNA RIVALE (al massimo 1, ~55% di probabilità)
  if (rngE() < 0.55) {
    const round = freeRound();
    const target = rivalNames[Math.floor(rngE()*Math.min(6, rivalNames.length))];
    const tpl = penaltyTemplates[Math.floor(rngE()*penaltyTemplates.length)];
    const pName = tpl.label === "CASO PLUSVALENZE" ? rosterName(target) : null;
    penalizeRival(target, tpl.pts); rivalPenDone = true;
    liveEvents.push({ round, kind:"penalty", title:tpl.label, text: tpl.txt(target, pName), club: target, pts: tpl.pts });
  }

  // 3) EVENTO DI COLORE (al massimo 1, ~45% di probabilità)
  if (rngE() < 0.45) {
    const round = freeRound();
    const txt = colorTemplates[Math.floor(rngE()*colorTemplates.length)];
    liveEvents.push({ round, kind:"color", title:"ULTIM'ORA", text: txt }); colorDone = true;
  }
  liveEvents.sort((a,b)=>a.round-b.round);

  const myFinalPts = Math.max(0, points - myPenalty);
  const realTable = [
    { club: "LA TUA SQUADRA", pts: myFinalPts, gd: GF-GA, me: true },
    ...oppResults.map(o => ({ ...o, gd: 0 })),
  ].sort((a,b)=> b.pts-a.pts || b.gd-a.gd);
  const realPos = realTable.findIndex(r => r.me) + 1;

  // ---- ONDATA 3: CAPOCANNONIERI della tua squadra ----
  const goalCount = {};
  matches.forEach(m => m.scorers.forEach(s => { goalCount[s.name] = (goalCount[s.name]||0)+1; }));
  const topScorers = Object.entries(goalCount)
    .map(([name, goals]) => ({ name, goals }))
    .sort((a,b)=> b.goals - a.goals)
    .slice(0, 5);

  // ---- ONDATA 3: striscia migliore / peggiore (per narrativa) ----
  let bestRun = 0, curRun = 0, worstRun = 0, curBad = 0;
  matches.forEach(m => {
    if (m.res === "W") { curRun++; bestRun = Math.max(bestRun, curRun); } else curRun = 0;
    if (m.res === "L") { curBad++; worstRun = Math.max(worstRun, curBad); } else curBad = 0;
  });
  const biggestWin = matches.reduce((b,m)=> (m.res==="W" && (m.gf-m.ga) > (b? b.gf-b.ga : -99)) ? m : b, null);
  const worstLoss  = matches.reduce((b,m)=> (m.res==="L" && (m.ga-m.gf) > (b? b.ga-b.gf : -99)) ? m : b, null);

  // ---- ONDATA 3: eventi casuali della stagione (deterministici dal seed) ----
  const rng3 = mulberry32(seed ^ 0x1a2b3c4d);
  const EVENTS = [
    { txt: "🩹 Un'ondata di infortuni a centrocampo ha messo alla prova la rosa.", w: 1 },
    { txt: "🔥 Lo spogliatoio ha trovato una chimica speciale a metà stagione.", w: 1 },
    { txt: "📣 La tifoseria ha spinto la squadra in ogni gara casalinga.", w: 1 },
    { txt: "⚖️ Qualche decisione arbitrale ha fatto discutere a lungo.", w: 1 },
    { txt: "🌧️ Un autunno di campi pesanti ha rallentato il gioco offensivo.", w: 1 },
    { txt: "💪 Il mercato di gennaio ha dato nuova linfa al gruppo.", w: 1 },
    { txt: "🧤 Il portiere ha vissuto una stagione da record di parate.", w: 1 },
  ];
  const pickEvents = () => {
    const pool = [...EVENTS];
    const out = [];
    for (let k=0; k<2 && pool.length; k++) {
      const idx = Math.floor(rng3() * pool.length);
      out.push(pool.splice(idx,1)[0].txt);
    }
    return out;
  };
  const events = pickEvents();

  // ---- ONDATA 3: titoli "Universo Sportivo" in base al rendimento ----
  const nTeams = opponents.length + 1;
  const news = [];
  if (W === nGames) news.push("🏆 IMPRESA STORICA: stagione perfetta, nessuna sconfitta!");
  else if (realPos === 1) news.push("🥇 CAMPIONI D'ITALIA: lo scudetto è tuo!");
  else if (realPos <= 4) news.push(`⭐ IN CHAMPIONS: ${ordinaleNews(realPos)} posto e qualificazione europea.`);
  else if (realPos >= (nTeams - 2)) news.push("🔻 STAGIONE DA INCUBO: la salvezza è a rischio.");
  if (bestRun >= 5) news.push(`🔥 Striscia da urlo: ${bestRun} vittorie consecutive.`);
  if (topScorers[0]) news.push(`⚽ ${topScorers[0].name} trascinatore con ${topScorers[0].goals} gol.`);
  if (biggestWin) news.push(`💥 Manita di giornata: ${biggestWin.gf}-${biggestWin.ga} ${biggestWin.home?"in casa":"in trasferta"} col ${biggestWin.opp}.`);
  liveEvents.filter(e=>e.kind==="penalty").forEach(e => news.push(`⚖️ ${e.club} penalizzata di ${e.pts} punti.`));
  liveEvents.filter(e=>e.kind==="own_penalty").forEach(e => news.push(`⚠️ La tua squadra penalizzata di ${e.pts} punti.`));
  liveEvents.filter(e=>e.kind==="own_player").forEach(() => news.push(`🩹 Stagione segnata dalla tegola sul tuo Super Sub.`));
  liveEvents.filter(e=>e.kind==="own_coach").forEach(() => news.push(`🤒 Allenatore ko per malattia in alcune gare chiave.`));
  if (news.length === 0) news.push("📰 Una stagione di alti e bassi per la tua squadra.");

  return {
    matches, W, D, L, GF, GA,
    points: myFinalPts,
    grossPoints: points,
    penalty: myPenalty,
    gd: GF - GA,
    season: playedSeason,
    nTeams,
    tier: tierForPosition(realPos, W),
    expectedPos, realPos,
    expectedTable, realTable,
    topScorers, events, news,
    bestRun, worstRun, biggestWin, worstLoss,
    liveEvents,
  };
}

// ================== CAMPO + POSIZIONI ==================
// layout posizioni per ogni formazione (x%, y%) — y dal basso (porta propria) all'alto
const POS = {
  "4-3-3": [[50,92],[82,72],[62,76],[38,76],[18,72],[50,55],[28,50],[72,50],[80,24],[50,16],[20,24]],
  "4-4-2": [[50,92],[82,72],[62,76],[38,76],[18,72],[80,46],[58,50],[42,50],[20,46],[60,18],[40,18]],
  "3-5-2": [[50,92],[66,78],[50,80],[34,78],[85,52],[64,52],[50,56],[36,52],[15,52],[60,20],[40,20]],
  "4-2-3-1": [[50,92],[82,72],[62,76],[38,76],[18,72],[62,56],[38,56],[50,38],[80,32],[20,32],[50,16]],
  "3-4-3": [[50,92],[68,76],[50,79],[32,76],[84,52],[60,54],[40,54],[16,52],[80,24],[50,18],[20,24]],
  "4-3-1-2": [[50,92],[82,72],[62,76],[38,76],[18,72],[30,52],[50,58],[70,52],[50,36],[62,18],[38,18]],
  "5-3-2": [[50,92],[88,68],[68,76],[50,79],[32,76],[12,68],[50,52],[30,50],[70,50],[60,20],[40,20]],
  "4-1-4-1": [[50,92],[82,72],[62,76],[38,76],[18,72],[50,60],[82,42],[60,44],[40,44],[18,42],[50,18]],
};

function Pitch({ formation, squad, activeIdx, highlightSlots = [], hideRatings }) {
  const layout = POS[formation.key] || POS["4-3-3"];
  return (
    <div style={{
      position:"relative", width:"100%", aspectRatio:"3/4", maxHeight:480, margin:"0 auto",
      background:`linear-gradient(${S.field},${S.fieldHi})`,
      borderRadius:14, border:`2px solid ${S.line}`, overflow:"hidden",
    }}>
      {/* righe campo */}
      <div style={pitchLines}/>
      <div style={{position:"absolute", top:"50%", left:0, right:0, height:2, background:"rgba(255,255,255,.15)"}}/>
      <div style={{position:"absolute", top:"50%", left:"50%", transform:"translate(-50%,-50%)",
        width:90, height:90, border:"2px solid rgba(255,255,255,.15)", borderRadius:"50%"}}/>

      {formation.slots.map((role, i) => {
        const [x,y] = layout[i];
        const p = squad[i];
        const active = i === activeIdx;
        const hl = highlightSlots.includes(i);
        return (
          <div key={i} style={{position:"absolute", left:`${x}%`, top:`${y}%`,
            transform:"translate(-50%,-50%)", textAlign:"center", width:74}}>
            <div style={{
              width:50, height:50, margin:"0 auto", borderRadius:"50%",
              display:"flex", alignItems:"center", justifyContent:"center",
              background: p ? S.cream : (hl ? "rgba(255,210,74,.25)" : "rgba(255,255,255,.08)"),
              border: (active||hl) ? `3px solid ${S.gold}` : `2px solid ${p?S.gold:"rgba(255,255,255,.25)"}`,
              boxShadow: (active||hl) ? `0 0 16px ${S.gold}` : "none",
              fontWeight:900, fontSize:p?13:11, color: p?S.ink:"rgba(255,255,255,.5)",
            }}>
              {p && !hideRatings ? p.rt : role}
            </div>
            {p && <div style={{fontSize:10, color:S.cream, fontWeight:700, marginTop:3,
              textShadow:"0 1px 2px #000", lineHeight:1.1}}>{p.n}</div>}
            {!p && <div style={{fontSize:9, color:"rgba(255,255,255,.4)", marginTop:3}}>{role}</div>}
          </div>
        );
      })}
    </div>
  );
}

