// ================== COMPONENTE PRINCIPALE ==================
// ================== ONDATA 2: BONUS PRE-PARTITA ==================
// 5 allenatori con bonus legato ai titoli vinti in Serie A
const COACHES = [
  { id:"allegri",   name:"Max Allegri",      titles:"6 scudetti",   bonus:0.3, emoji:"🎩" },
  { id:"conte",     name:"Antonio Conte",    titles:"4 scudetti",   bonus:0.3, emoji:"🔥" },
  { id:"spalletti",  name:"Luciano Spalletti", titles:"1 scudetto",  bonus:0.2, emoji:"🧠" },
  { id:"gasperini", name:"Gian Piero Gasperini", titles:"gioco offensivo", bonus:0.2, emoji:"⚡" },
  { id:"nessuno",   name:"Nessun allenatore", titles:"vai a istinto", bonus:0,   emoji:"🚫" },
];

// Capitano: bonus in base al tier di rating del giocatore scelto come capitano
function captainBonus(rt) {
  if (rt >= 89) return 0.4;
  if (rt >= 85) return 0.3;
  if (rt >= 80) return 0.2;
  return 0.1;
}

// indice del giocatore più debole (per Super Sub)
function weakestIdx(squad) {
  let idx = -1, min = Infinity;
  squad.forEach((p,i) => { if (p && p.rt < min) { min = p.rt; idx = i; } });
  return idx;
}

function BonusSelect({ squad, formation, usedIds, teamClub = null, onConfirm }) {
  const filled = squad.filter(Boolean);
  // CAPITANO
  const [captainPid, setCaptainPid] = useState(null);
  // ALLENATORE
  const [coachId, setCoachId] = useState("nessuno");
  // SUPER SUB
  const weakIdx = useMemo(()=>weakestIdx(squad), [squad]);
  const weakPlayer = weakIdx >= 0 ? squad[weakIdx] : null;
  const [subPlayer, setSubPlayer] = useState(null);   // sostituto scelto
  const [subSpin, setSubSpin] = useState(null);        // {club, season, candidates}
  const [subSpinning, setSubSpinning] = useState(false);
  const [subDone, setSubDone] = useState(false);       // ha deciso (scelto o saltato)

  const weakRole = weakPlayer ? weakPlayer.slot : null;

  const spinSub = useCallback(() => {
    if (!weakRole) return;
    setSubSpinning(true); setSubPlayer(null);
    let attempt = 0, found = null;
    while (attempt < 400 && !found) {
      const club = teamClub || pick(CLUBS), season = pick(SEASONS);
      const pool = PLAYERS.filter(p => p.c===club && p.s===season &&
        !usedIds.has(p.pid) && eligibleFor(p, weakRole) && p.rt > weakPlayer.rt);
      if (pool.length > 0) found = { club, season, candidates: pool.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      attempt++;
    }
    if (!found) {
      const pool = PLAYERS.filter(p => !usedIds.has(p.pid) && eligibleFor(p, weakRole) && p.rt > weakPlayer.rt && (teamClub ? p.c===teamClub : true));
      if (pool.length) {
        const p0 = pick(pool);
        const cand = PLAYERS.filter(p => p.c===p0.c && p.s===p0.s && !usedIds.has(p.pid) && eligibleFor(p,weakRole) && p.rt>weakPlayer.rt);
        found = { club:p0.c, season:p0.s, candidates: cand.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      }
    }
    setTimeout(()=>{ setSubSpin(found); setSubSpinning(false); if(!found) setSubDone(true); }, 1000);
  }, [weakRole, weakPlayer, usedIds, teamClub]);

  // calcolo bonus totale + squad finale
  const coach = COACHES.find(c=>c.id===coachId);
  const capPlayer = captainPid ? filled.find(p=>p.pid===captainPid) : null;
  const capB = capPlayer ? captainBonus(capPlayer.rt) : 0;
  const coachB = coach ? coach.bonus : 0;
  // Super Sub: il delta di rating del sostituto migliora la media -> lo traduciamo in bonus forza
  const subB = subPlayer ? Math.min(1.0, (subPlayer.rt - weakPlayer.rt) * 0.12) : 0;
  const bonusTotal = Math.round((capB + coachB + subB) * 100) / 100;

  const confirm = () => {
    let finalSquad = squad;
    let superSub = null;
    if (subPlayer && weakIdx >= 0) {
      finalSquad = [...squad];
      finalSquad[weakIdx] = { ...subPlayer, slot: weakRole, isSuperSub: true };
      superSub = { ...subPlayer, slot: weakRole };
    }
    onConfirm({
      bonusTotal,
      coach: coach && coach.id !== "nessuno" ? coach : null,
      captain: capPlayer || null,
      superSub,
      finalSquad,
    });
  };

  const sectionTitle = { color:S.gold, fontSize:16, fontWeight:900, letterSpacing:1, marginBottom:4 };
  const sectionSub = { color:S.cream, opacity:.6, fontSize:12, marginBottom:12 };

  return (
    <div style={wrap}>
      <div style={{maxWidth:640, margin:"0 auto", padding:"24px 16px"}}>
        <div style={{textAlign:"center", marginBottom:8}}>
          <div style={{color:S.gold, fontSize:13, letterSpacing:3, opacity:.8}}>PRIMA DEL FISCHIO D'INIZIO</div>
          <div style={{color:S.cream, fontSize:26, fontWeight:900, letterSpacing:1}}>Scegli i tuoi bonus</div>
        </div>

        {/* CAPITANO */}
        <div style={{...panel, marginTop:18}}>
          <div style={sectionTitle}>🅒 Capitano</div>
          <div style={sectionSub}>La fascia dà carattere: bonus in base al rating del prescelto.</div>
          <div style={{display:"flex", flexWrap:"wrap", gap:8}}>
            {filled.sort((a,b)=>b.rt-a.rt).map(p => {
              const on = captainPid === p.pid;
              return (
                <div key={p.pid} onClick={()=>setCaptainPid(on?null:p.pid)}
                  style={{...chip(on), flex:"1 1 46%", display:"flex", justifyContent:"space-between", alignItems:"center"}}>
                  <span style={{overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{p.slot} · {p.n}</span>
                  <span style={{fontWeight:900, marginLeft:8}}>{p.rt}</span>
                </div>
              );
            })}
          </div>
          {capPlayer && <div style={{color:S.gold, fontSize:13, marginTop:10, fontWeight:700}}>
            Capitano: {capPlayer.n} → +{capB.toFixed(2)} forza
          </div>}
        </div>

        {/* ALLENATORE */}
        <div style={{...panel, marginTop:14}}>
          <div style={sectionTitle}>🎩 Allenatore</div>
          <div style={sectionSub}>Una grande guida vale punti pesanti.</div>
          <div style={{display:"flex", flexDirection:"column", gap:8}}>
            {COACHES.map(c => {
              const on = coachId === c.id;
              return (
                <div key={c.id} onClick={()=>setCoachId(c.id)}
                  style={{...chip(on), flex:"1 1 auto", display:"flex", justifyContent:"space-between", alignItems:"center"}}>
                  <span>{c.emoji} {c.name} <span style={{opacity:.6, fontSize:12}}>· {c.titles}</span></span>
                  <span style={{fontWeight:900}}>{c.bonus>0?`+${c.bonus.toFixed(1)}`:"—"}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* SUPER SUB */}
        <div style={{...panel, marginTop:14}}>
          <div style={sectionTitle}>🔁 Super Sub</div>
          {weakPlayer ? (<>
            <div style={sectionSub}>
              Il tuo anello debole è <b style={{color:S.cream}}>{weakPlayer.n}</b> ({weakPlayer.slot} · {weakPlayer.rt}).
              Gira per pescare un sostituto migliore, oppure tienilo.
            </div>
            {!subDone && !subSpin && !subSpinning && (
              <div style={{display:"flex", gap:8}}>
                <button onClick={spinSub} style={{...bigBtnSm, flex:1}}>🎡 Gira sostituto</button>
                <button onClick={()=>setSubDone(true)} style={{...bigBtnSm, flex:1, background:"rgba(0,0,0,.25)", color:S.cream, border:`2px solid ${S.line}`}}>Tieni {weakPlayer.n}</button>
              </div>
            )}
            {subSpinning && <div style={spinningBox}>🎡 Pesco un sostituto…</div>}
            {subSpin && !subPlayer && (
              <div>
                <div style={{color:S.cream, opacity:.7, fontSize:12, margin:"4px 0 8px"}}>
                  {subSpin.club} · {subSpin.season}
                </div>
                <div style={{display:"flex", flexWrap:"wrap", gap:8}}>
                  {subSpin.candidates.map(p => (
                    <div key={p.pid} onClick={()=>{setSubPlayer(p); setSubDone(true);}}
                      style={{...chip(false), flex:"1 1 46%", display:"flex", justifyContent:"space-between"}}>
                      <span style={{overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{p.n}</span>
                      <span style={{fontWeight:900, color:S.gold}}>{p.rt}</span>
                    </div>
                  ))}
                </div>
                <button onClick={()=>setSubDone(true)} style={{...bigBtnSm, marginTop:10, background:"rgba(0,0,0,.25)", color:S.cream, border:`2px solid ${S.line}`}}>Nessuno, tieni {weakPlayer.n}</button>
              </div>
            )}
            {subPlayer && <div style={{color:S.gold, fontSize:13, marginTop:10, fontWeight:700}}>
              Dentro {subPlayer.n} ({subPlayer.rt}) per {weakPlayer.n} → +{subB.toFixed(2)} forza
            </div>}
          </>) : (
            <div style={sectionSub}>Rosa incompleta.</div>
          )}
        </div>

        {/* RIEPILOGO + AVVIA */}
        <div style={{...panel, marginTop:14, textAlign:"center"}}>
          <div style={{color:S.cream, opacity:.7, fontSize:13}}>Bonus forza totale</div>
          <div style={{color:S.gold, fontSize:34, fontWeight:900}}>+{bonusTotal.toFixed(2)}</div>
        </div>
        <button onClick={confirm} style={bigBtn}>⚽ INIZIA LA STAGIONE</button>
      </div>
    </div>
  );
}

// ================== ONDATA 4: MERCATO + EVOLUZIONE (fine stagione carriera) ==================
function Market({ squad, formation, usedIds, forcedSeason, careerYear, careerEvo, difficulty = "normal", teamClub = null, onConfirm }) {
  const MAX_SUBS = 3;
  const BASE_REROLLS = DIFFICULTY[difficulty]?.rerolls ?? 0; // rigirate per sostituzione = reroll della modalità
  const [roster, setRoster] = useState(squad);
  const [ids, setIds] = useState(()=>{ const s=new Set(); squad.forEach(p=>p&&s.add(p.pid)); return s; });
  const [subsLeft, setSubsLeft] = useState(MAX_SUBS);
  const [targetIdx, setTargetIdx] = useState(null);  // slot in sostituzione
  const [spin, setSpin] = useState(null);
  const [spinning, setSpinning] = useState(false);
  const [rerollsLeft, setRerollsLeft] = useState(BASE_REROLLS); // rigirate residue per la sostituzione corrente

  // in Modalità Squadra i rimpiazzi vengono SOLO dalle rose del club (tutte le stagioni)
  const seasonPool = teamClub ? REAL_SEASONS : (forcedSeason ? [forcedSeason] : SEASONS);

  const doSpin = useCallback((slotIdx) => {
    const slotRole = formation.slots[slotIdx];
    setSpinning(true); setSpin(null);
    let attempt = 0, found = null;
    while (attempt < 400 && !found) {
      const club = teamClub || pick(CLUBS), season = pick(seasonPool);
      const pool = PLAYERS.filter(p => p.c===club && p.s===season && !ids.has(p.pid) && eligibleFor(p, slotRole));
      if (pool.length) found = { club, season, candidates: pool.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      attempt++;
    }
    if (!found) {
      const pool = PLAYERS.filter(p => !ids.has(p.pid) && eligibleFor(p, slotRole) && (teamClub ? p.c===teamClub : (!forcedSeason || p.s===forcedSeason)));
      if (pool.length) { const p0=pick(pool);
        const cand = PLAYERS.filter(p=>p.c===p0.c && p.s===p0.s && !ids.has(p.pid) && eligibleFor(p,slotRole));
        found = { club:p0.c, season:p0.s, candidates:cand.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      }
    }
    setTimeout(()=>{ setSpin(found); setSpinning(false); }, 900);
  }, [formation, ids, seasonPool, forcedSeason, teamClub]);

  const startSub = (slotIdx) => { if (subsLeft<=0) return; setTargetIdx(slotIdx); setRerollsLeft(BASE_REROLLS); doSpin(slotIdx); };
  const confirmSub = (player) => {
    const slotRole = formation.slots[targetIdx];
    setRoster(prev => { const n=[...prev]; const old=n[targetIdx]; 
      n[targetIdx] = { ...player, slot:slotRole };
      setIds(s=>{ const ns=new Set(s); if(old) ns.delete(old.pid); ns.add(player.pid); return ns; });
      return n; });
    setSubsLeft(s=>s-1); setTargetIdx(null); setSpin(null);
  };

  return (
    <div style={wrap}>
      <Header small />
      <div style={{maxWidth:680, margin:"0 auto", padding:"0 16px"}}>
        <div style={{...panel, textAlign:"center"}}>
          <div style={{fontSize:13, fontWeight:900, letterSpacing:1.5, color:S.gold}}>🗓️ FINE STAGIONE {careerYear}</div>
          <div style={{color:S.cream, opacity:.7, fontSize:14, marginTop:6}}>I tuoi giocatori sono cresciuti o invecchiati. Puoi sostituirne fino a <b style={{color:S.gold}}>{MAX_SUBS}</b>.</div>
        </div>

        {careerEvo && careerEvo.length>0 && (
          <div style={{...panel, marginTop:14}}>
            <div style={{color:S.gold, fontSize:13, fontWeight:900, letterSpacing:1.5, marginBottom:12}}>📈 EVOLUZIONE RATING</div>
            <div style={{display:"flex", flexDirection:"column", gap:6}}>
              {careerEvo.map((e,i)=>(
                <div key={i} style={{display:"flex", alignItems:"center", gap:10, fontSize:13}}>
                  <span style={{width:42, color:S.cream, opacity:.5, fontSize:11}}>{e.slot}</span>
                  <span style={{flex:1, color:S.cream}}>{e.n} <span style={{opacity:.4, fontSize:11}}>({e.age}a)</span></span>
                  <span style={{color:S.cream, opacity:.5}}>{e.oldRt}</span>
                  <span style={{opacity:.4}}>→</span>
                  <span style={{fontWeight:900, color: e.delta>0?"#6ee7a8":e.delta<0?"#ff8e8e":S.cream}}>{e.newRt}</span>
                  <span style={{width:36, textAlign:"right", fontWeight:700, fontSize:12, color: e.delta>0?"#6ee7a8":e.delta<0?"#ff8e8e":S.cream, opacity:e.delta===0?.4:1}}>{e.delta>0?"+":""}{e.delta||"="}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div style={{...panel, marginTop:14}}>
          <div style={{display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12}}>
            <div style={{color:S.gold, fontSize:13, fontWeight:900, letterSpacing:1.5}}>🔁 MERCATO</div>
            <div style={{fontSize:12, color:S.cream, opacity:.7}}>Sostituzioni rimaste: <b style={{color:S.gold}}>{subsLeft}</b></div>
          </div>
          <div style={{display:"flex", flexDirection:"column", gap:6}}>
            {roster.map((p,i)=> p && (
              <div key={i} style={{display:"flex", alignItems:"center", gap:10, fontSize:13, padding:"6px 0", borderBottom:"1px solid rgba(244,236,216,.08)"}}>
                <span style={{width:42, color:S.cream, opacity:.5, fontSize:11}}>{p.slot}</span>
                <span style={{flex:1, color:S.cream}}>{p.n} <span style={{opacity:.4, fontSize:11}}>{p.c} · {p.s}</span></span>
                <span style={ratBadge}>{p.rt}</span>
                <button disabled={subsLeft<=0} onClick={()=>startSub(i)}
                  style={{...chip(false), fontSize:11, padding:"5px 9px", opacity:subsLeft<=0?.35:1, cursor:subsLeft<=0?"not-allowed":"pointer"}}>
                  cambia
                </button>
              </div>
            ))}
          </div>
        </div>

        {targetIdx!==null && (
          <div style={{...panel, marginTop:14, borderColor:S.gold}}>
            <div style={{color:S.gold, fontSize:13, fontWeight:900, marginBottom:10}}>
              Sostituto per {formation.slots[targetIdx]} {spin && <span style={{opacity:.6, fontWeight:400}}>· {spin.club} {spin.season}</span>}
            </div>
            {spinning && <div style={{textAlign:"center", color:S.cream, opacity:.7, padding:20}}>🎰 Pesco...</div>}
            {spin && !spinning && (
              <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:8}}>
                {spin.candidates.map(c=>(
                  <button key={c.id} onClick={()=>confirmSub(c)} style={cardBtn}>
                    <div style={{fontWeight:700, fontSize:14, color:S.ink}}>{c.n}</div>
                    <div style={{fontSize:11, color:"#2c5f48", marginTop:2}}>{c.rg.join("/")} · {c.age}a
                      <span style={ratBadge}>{c.rt}</span></div>
                  </button>
                ))}
              </div>
            )}
            <div style={{display:"flex", gap:8, marginTop:10}}>
              {rerollsLeft>0
                ? <button onClick={()=>{ setRerollsLeft(r=>r-1); doSpin(targetIdx); }} style={{...chip(false), fontSize:12}}>🎰 Rigira ({rerollsLeft})</button>
                : <span style={{fontSize:11, color:S.cream, opacity:.45, alignSelf:"center"}}>Nessuna rigirata · scegli tra i candidati</span>}
              <button onClick={()=>{setTargetIdx(null); setSpin(null);}} style={{...chip(false), fontSize:12}}>Annulla</button>
            </div>
          </div>
        )}

        <button onClick={()=>onConfirm(roster, ids)} style={{...bigBtn, marginTop:16}}>▶ AVANTI ALLA STAGIONE {careerYear+1}</button>
      </div>
    </div>
  );
}

export default function App() {
  const [phase, setPhase] = useState("setup"); // setup | draft | bonus | season | result | market
  const [formationKey, setFormationKey] = useState("4-3-3");
  const [difficulty, setDifficulty] = useState("normal");
  const [draftMode, setDraftMode] = useState("position"); // position | squad
  const [pickMode, setPickMode] = useState("realistica"); // realistica | normale | facile
  const [seasonMode, setSeasonMode] = useState("random"); // random | scelta
  const [chosenSeason, setChosenSeason] = useState(ALL_SEASONS[ALL_SEASONS.length-1]);
  // ---- Modalità Squadra: pesca solo dalle rose di un club, che prende il tuo posto in campionato ----
  // VERSIONE ROMA: la modalità squadra è sempre attiva e il club è fissato sulla Roma.
  const teamMode = true;
  const chosenTeam = "Roma";

  const formation = FORMATIONS[formationKey];
  const [squad, setSquad] = useState([]);        // array allineato a slots
  const [round, setRound] = useState(0);         // n. slot riempiti (Position First = indice slot)
  const [rerolls, setRerolls] = useState(0);
  const [spin, setSpin] = useState(null);        // {club, season, candidates}
  const [spinning, setSpinning] = useState(false);
  const [usedIds, setUsedIds] = useState(new Set());
  const [pendingPlayer, setPendingPlayer] = useState(null); // Squad First: giocatore in attesa di slot

  // ---- ONDATA 2: bonus pre-partita ----
  const [bonusTotal, setBonusTotal] = useState(0);
  const [coach, setCoach] = useState(null);
  const [captain, setCaptain] = useState(null);
  const [superSub, setSuperSub] = useState(null);
  // Normale: 5 pescaggi (non tra gli ultimi) ESENTI dal vincolo 80+
  const [freePicks, setFreePicks] = useState(new Set());

  // ---- ONDATA 4: modalità carriera ----
  const [careerMode, setCareerMode] = useState(false); // opt-in dal Setup
  const [careerYear, setCareerYear] = useState(1);      // stagione n. della carriera
  const [careerHistory, setCareerHistory] = useState([]); // [{year, pos, points, tier}]
  const [careerEvo, setCareerEvo] = useState(null);     // dettaglio evoluzione ultima stagione

  // slot liberi (indici)
  const openSlots = useCallback((sq) =>
    formation.slots.map((r,i)=>({r,i})).filter(({i}) => !sq[i]),
    [formation]);

  // avvia partita
  const startGame = useCallback(() => {
    const nSlots = formation.slots.length;
    setSquad(new Array(nSlots).fill(null));
    setRound(0);
    setRerolls(DIFFICULTY[difficulty].rerolls);
    setUsedIds(new Set());
    setSpin(null);
    setPendingPlayer(null);
    setBonusTotal(0); setCoach(null); setCaptain(null); setSuperSub(null);
    // Normale: 5 pescaggi liberi dal vincolo 80+, scelti tra i primi (mai negli ultimi 3)
    const fp = new Set();
    if (pickMode === "normale") {
      const maxIdx = Math.max(0, nSlots - 4); // indici 0..maxIdx ammessi
      const target = Math.min(5, maxIdx + 1);
      let guard = 0;
      while (fp.size < target && guard < 200) {
        fp.add(Math.floor(Math.random() * (maxIdx + 1)));
        guard++;
      }
    }
    setFreePicks(fp);
    setCareerYear(1); setCareerHistory([]); setCareerEvo(null);
    setPhase("draft");
  }, [formation, difficulty, pickMode]);

  // ---- POSITION FIRST: spin con candidati validi per lo slot corrente ----
  const doSpinPosition = useCallback(() => {
    if (round >= formation.slots.length) return;
    const slotRole = formation.slots[round];
    setSpinning(true);
    const seasonPool = teamMode ? REAL_SEASONS : (seasonMode === "scelta" ? [chosenSeason] : SEASONS);
    // VINCOLO 80+ (Normale/Facile): OGNI pescata deve offrire almeno un giocatore da 80+
    // tra i candidati. NON si escludono i sotto-80: restano nella lista, ma è garantito
    // che ci sia sempre almeno una scelta da 80+ selezionabile.
    // In Normale, 5 pescaggi (freePicks) sono ESENTI dal vincolo.
    // In Modalità Squadra: pesca LIBERA dalla rosa del club, nessun vincolo 80+.
    const wants80 = !teamMode && (pickMode === "facile" || pickMode === "normale") && !freePicks.has(round);
    let attempt = 0, found = null;
    while (attempt < 400 && !found) {
      const club = teamMode ? chosenTeam : pick(CLUBS), season = pick(seasonPool);
      const pool = PLAYERS.filter(p => p.c===club && p.s===season &&
        !usedIds.has(p.pid) && eligibleFor(p, slotRole));
      if (pool.length === 0) { attempt++; continue; }
      // se richiediamo 80+, accetta questa pescata solo se contiene almeno un 80+
      if (wants80 && !pool.some(p => p.rt >= 80)) { attempt++; continue; }
      found = { club, season, candidates: pool.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      attempt++;
    }
    if (!found) {
      // fallback: cerca direttamente un 80+ idoneo (se esiste), altrimenti chiunque
      let pool = PLAYERS.filter(p => !usedIds.has(p.pid) && eligibleFor(p, slotRole)
        && (teamMode ? p.c === chosenTeam : (seasonMode !== "scelta" || p.s === chosenSeason)));
      const pool80 = pool.filter(p => p.rt >= 80);
      const base = (wants80 && pool80.length) ? pool80 : pool;
      if (base.length) {
        const p0 = pick(base);
        const cand = PLAYERS.filter(p => p.c===p0.c && p.s===p0.s && !usedIds.has(p.pid) && eligibleFor(p,slotRole));
        found = { club: p0.c, season: p0.s, candidates: cand.sort((a,b)=>b.rt-a.rt).slice(0,6) };
      }
    }
    setTimeout(()=>{ setSpin(found); setSpinning(false); }, 1100);
  }, [round, formation, usedIds, pickMode, seasonMode, chosenSeason, freePicks, teamMode, chosenTeam]);

  // ---- SQUAD FIRST: spin club+stagione, candidati = chi entra in QUALSIASI slot libero ----
  const doSpinSquad = useCallback(() => {
    const slots = formation.slots;
    const open = slots.map((r,i)=>({r,i})).filter(({i}) => !squad[i]);
    if (open.length === 0) return;
    const filled = slots.length - open.length;
    const openRoles = [...new Set(open.map(o=>o.r))];
    const allRoles = [...new Set(slots)];
    const fitsAny = (p) => openRoles.some(role => eligibleFor(p, role));        // piazzabile ORA
    const fitsFormation = (p) => allRoles.some(role => eligibleFor(p, role));   // idoneo a un ruolo della formazione
    setSpinning(true);
    const seasonPool = teamMode ? REAL_SEASONS : (seasonMode === "scelta" ? [chosenSeason] : SEASONS);
    // VINCOLO 80+ (Normale/Facile): ogni pescata deve offrire almeno un 80+ PIAZZABILE ora.
    // In Normale, 5 pescaggi (freePicks, indicizzati sul n. di giocatori già piazzati) sono ESENTI.
    // In Modalità Squadra: pesca LIBERA dalla rosa del club, nessun vincolo 80+.
    const wants80 = !teamMode && (pickMode === "facile" || pickMode === "normale") && !freePicks.has(filled);
    // mappa candidati di un club/stagione: include anche i non-piazzabili (ruolo pieno),
    // marcati playable:false così l'utente li VEDE ma non può sceglierli.
    const buildCands = (club, season) =>
      PLAYERS.filter(p => p.c===club && p.s===season && !usedIds.has(p.pid) && fitsFormation(p))
        .map(p => ({ ...p, playable: fitsAny(p) }))
        .sort((a,b)=> (b.playable-a.playable) || (b.rt-a.rt))
        .slice(0,10);
    let attempt = 0, found = null;
    while (attempt < 400 && !found) {
      const club = teamMode ? chosenTeam : pick(CLUBS), season = pick(seasonPool);
      // serve almeno un giocatore PIAZZABILE in questo club/stagione
      const placeable = PLAYERS.filter(p => p.c===club && p.s===season && !usedIds.has(p.pid) && fitsAny(p));
      if (placeable.length === 0) { attempt++; continue; }
      // se richiediamo 80+, accetta solo se c'è un 80+ piazzabile
      if (wants80 && !placeable.some(p => p.rt >= 80)) { attempt++; continue; }
      found = { club, season, candidates: buildCands(club, season) };
      attempt++;
    }
    if (!found) {
      let pool = PLAYERS.filter(p => !usedIds.has(p.pid) && fitsAny(p)
        && (teamMode ? p.c === chosenTeam : (seasonMode !== "scelta" || p.s === chosenSeason)));
      const pool80 = pool.filter(p => p.rt >= 80);
      const base = (wants80 && pool80.length) ? pool80 : pool;
      if (base.length) {
        const p0 = pick(base);
        found = { club: p0.c, season: p0.s, candidates: buildCands(p0.c, p0.s) };
      }
    }
    setTimeout(()=>{ setSpin(found); setSpinning(false); }, 1100);
  }, [formation, squad, usedIds, pickMode, seasonMode, chosenSeason, freePicks, teamMode, chosenTeam]);

  const doSpin = draftMode === "squad" ? doSpinSquad : doSpinPosition;

  const reroll = useCallback(() => {
    if (rerolls <= 0) return;
    setRerolls(r => r-1);
    setSpin(null);
    setPendingPlayer(null);
    setTimeout(doSpin, 50);
  }, [rerolls, doSpin]);

  // helper: piazza un giocatore in uno slot specifico
  const placeIn = useCallback((player, slotIdx) => {
    const slotRole = formation.slots[slotIdx];
    setSquad(prev => {
      const next = [...prev];
      next[slotIdx] = { ...player, slot: slotRole };
      const filled = next.filter(Boolean).length;
      if (filled >= formation.slots.length) setTimeout(()=>setPhase("bonus"), 300);
      return next;
    });
    setUsedIds(prev => new Set(prev).add(player.pid));
    setSpin(null);
    setPendingPlayer(null);
    setRound(r => r+1);
  }, [formation]);

  // POSITION FIRST: scelto il giocatore -> va nello slot del round
  // SQUAD FIRST: scelto il giocatore -> se entra in 1 solo slot libero piazza, altrimenti chiede lo slot
  const choose = useCallback((player) => {
    if (draftMode === "position") {
      placeIn(player, round);
      return;
    }
    // squad first
    const open = formation.slots.map((r,i)=>({r,i})).filter(({i}) => !squad[i]);
    const fitting = open.filter(({r}) => eligibleFor(player, r));
    if (fitting.length === 1) {
      placeIn(player, fitting[0].i);
    } else {
      setPendingPlayer({ player, options: fitting });
    }
  }, [draftMode, round, formation, squad, placeIn]);

  const hideRatings = DIFFICULTY[difficulty].hideRatings;
  const filledCount = squad.filter(Boolean).length;
  const forcedSeason = seasonMode === "scelta" ? chosenSeason : null;

  // ---- ONDATA 4: avanza alla stagione successiva (evolve la rosa, poi mercato) ----
  const advanceCareer = useCallback((perf) => {
    const seed = (careerYear * 2654435761) >>> 0;
    const evolved = evolveSquad(squad, perf, seed);
    setCareerEvo(evolved.map(p => p ? { n:p.n, slot:p.slot, oldRt:p.rt - (p._evo?.delta||0), newRt:p.rt, age:p.age, delta:p._evo?.delta||0 } : null).filter(Boolean));
    setSquad(evolved);
    const ids = new Set(); evolved.forEach(p => p && ids.add(p.pid));
    setUsedIds(ids);
    setPhase("market");
  }, [squad, careerYear]);

  // ---- ONDATA 4: conferma il mercato e parte la nuova stagione ----
  const finishMarket = useCallback((newSquad, newUsedIds) => {
    setSquad(newSquad);
    setUsedIds(newUsedIds);
    setCareerYear(y => y + 1);
    setBonusTotal(0); setCoach(null); setCaptain(null); setSuperSub(null);
    setPhase("bonus"); // nuova stagione: si ripassa dai bonus pre-partita
  }, []);

  // ============ RENDER ============
  if (phase === "setup") return <Setup {...{formationKey,setFormationKey,difficulty,setDifficulty,draftMode,setDraftMode,pickMode,setPickMode,seasonMode,setSeasonMode,chosenSeason,setChosenSeason,careerMode,setCareerMode,teamMode,chosenTeam,startGame}} />;
  if (phase === "bonus") return <BonusSelect {...{squad, formation, usedIds, teamClub: teamMode ? chosenTeam : null, onConfirm:({bonusTotal,coach,captain,superSub,finalSquad})=>{ setSquad(finalSquad); if(finalSquad!==squad){ const s=new Set(usedIds); finalSquad.forEach(p=>p&&s.add(p.pid)); setUsedIds(s);} setBonusTotal(bonusTotal); setCoach(coach); setCaptain(captain); setSuperSub(superSub); setPhase("season"); }}} />;
  if (phase === "season") return <SeasonLive {...{squad, formation, forcedSeason, bonusTotal, coach, captain, superSub, excludeClub: teamMode ? chosenTeam : null, onDone:()=>setPhase("result")}} />;
  if (phase === "result") return <Result {...{squad, formation, forcedSeason, bonusTotal, coach, captain, superSub, excludeClub: teamMode ? chosenTeam : null, careerMode, careerYear, onRestart:()=>setPhase("setup"), onAdvance:advanceCareer}} />;
  if (phase === "market") return <Market {...{squad, formation, usedIds, forcedSeason, careerYear, careerEvo, difficulty, teamClub: teamMode ? chosenTeam : null, onConfirm:finishMarket}} />;

  return (
    <Draft {...{formation, squad, round, filledCount, spin, spinning, doSpin, reroll, rerolls,
      choose, hideRatings, difficulty, draftMode, pendingPlayer, placeIn, careerMode,
      cancelPending:()=>setPendingPlayer(null)}} />
  );
}

